/**
 * Self-contained HTML template for PR review reports.
 * The string __PR_DATA__ is replaced with the JSON.stringify'd PRAnalysis object.
 */
export declare const REPORT_TEMPLATE = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>PR Review</title>\n  <style>\n    :root {\n      --bg: #0d1117;\n      --surface: #161b22;\n      --surface-2: #21262d;\n      --border: #30363d;\n      --text: #c9d1d9;\n      --text-muted: #8b949e;\n      --accent: #58a6ff;\n      --high: #f85149;\n      --high-bg: rgba(248,81,73,0.12);\n      --medium: #d29922;\n      --medium-bg: rgba(210,153,34,0.12);\n      --low: #3fb950;\n      --low-bg: rgba(63,185,80,0.12);\n    }\n    * { box-sizing: border-box; margin: 0; padding: 0; }\n    body {\n      background: var(--bg);\n      color: var(--text);\n      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;\n      font-size: 14px;\n      line-height: 1.6;\n    }\n    a { color: var(--accent); text-decoration: none; }\n\n    /* \u2500\u2500 Header \u2500\u2500 */\n    .header {\n      background: var(--surface);\n      border-bottom: 1px solid var(--border);\n      padding: 24px 32px;\n    }\n    .header h1 {\n      font-size: 18px;\n      font-weight: 600;\n      margin-bottom: 10px;\n    }\n    .branch-row {\n      display: flex;\n      align-items: center;\n      gap: 8px;\n      font-size: 13px;\n      color: var(--text-muted);\n    }\n    .branch-pill {\n      background: var(--surface-2);\n      border: 1px solid var(--border);\n      border-radius: 12px;\n      padding: 2px 10px;\n      font-family: 'Courier New', monospace;\n      color: var(--accent);\n      font-size: 12px;\n    }\n    .stats-bar {\n      display: flex;\n      gap: 28px;\n      margin-top: 18px;\n      padding-top: 18px;\n      border-top: 1px solid var(--border);\n      align-items: center;\n    }\n    .stat { display: flex; flex-direction: column; }\n    .stat-value { font-size: 22px; font-weight: 700; line-height: 1.2; }\n    .stat-label { font-size: 11px; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.6px; margin-top: 2px; }\n    .added { color: #3fb950; }\n    .removed { color: #f85149; }\n\n    /* \u2500\u2500 Risk badges \u2500\u2500 */\n    .risk {\n      display: inline-flex;\n      align-items: center;\n      gap: 4px;\n      padding: 2px 9px;\n      border-radius: 12px;\n      font-size: 11px;\n      font-weight: 700;\n      text-transform: uppercase;\n      letter-spacing: 0.5px;\n    }\n    .risk.high   { color: var(--high);   background: var(--high-bg);   border: 1px solid rgba(248,81,73,0.35); }\n    .risk.medium { color: var(--medium); background: var(--medium-bg); border: 1px solid rgba(210,153,34,0.35); }\n    .risk.low    { color: var(--low);    background: var(--low-bg);    border: 1px solid rgba(63,185,80,0.35); }\n\n    /* \u2500\u2500 Type badges \u2500\u2500 */\n    .type-badge {\n      display: inline-block;\n      padding: 1px 7px;\n      border-radius: 4px;\n      font-size: 11px;\n      font-weight: 600;\n      text-transform: uppercase;\n      letter-spacing: 0.3px;\n    }\n    .type-badge.added    { color: #3fb950; background: rgba(63,185,80,0.15); }\n    .type-badge.modified { color: #79c0ff; background: rgba(121,192,255,0.15); }\n    .type-badge.deleted  { color: #f85149; background: rgba(248,81,73,0.15); }\n    .type-badge.renamed  { color: #d29922; background: rgba(210,153,34,0.15); }\n\n    /* \u2500\u2500 Nav \u2500\u2500 */\n    .nav {\n      background: var(--surface);\n      border-bottom: 1px solid var(--border);\n      padding: 0 28px;\n      display: flex;\n      gap: 2px;\n      position: sticky;\n      top: 0;\n      z-index: 200;\n    }\n    .nav a {\n      padding: 11px 14px;\n      color: var(--text-muted);\n      font-size: 13px;\n      font-weight: 500;\n      border-bottom: 2px solid transparent;\n      transition: color 0.15s, border-color 0.15s;\n      white-space: nowrap;\n    }\n    .nav a:hover { color: var(--text); }\n    .nav a.active { color: var(--text); border-bottom-color: var(--accent); }\n\n    /* \u2500\u2500 Main \u2500\u2500 */\n    .main {\n      max-width: 1080px;\n      margin: 0 auto;\n      padding: 32px;\n    }\n    .section { margin-bottom: 44px; }\n    .section-title {\n      font-size: 15px;\n      font-weight: 600;\n      margin-bottom: 14px;\n      padding-bottom: 10px;\n      border-bottom: 1px solid var(--border);\n      display: flex;\n      align-items: center;\n      gap: 8px;\n    }\n    .count { background: var(--surface-2); border-radius: 12px; padding: 2px 8px; font-size: 12px; color: var(--text-muted); }\n    .empty { color: var(--text-muted); font-size: 13px; font-style: italic; }\n\n    /* \u2500\u2500 Summary card \u2500\u2500 */\n    .summary-card {\n      background: var(--surface);\n      border: 1px solid var(--border);\n      border-radius: 8px;\n      padding: 20px;\n      font-size: 14px;\n      line-height: 1.7;\n    }\n\n    /* \u2500\u2500 Change cards \u2500\u2500 */\n    .change-card {\n      background: var(--surface);\n      border: 1px solid var(--border);\n      border-radius: 8px;\n      margin-bottom: 6px;\n      overflow: hidden;\n      transition: border-color 0.15s;\n    }\n    .change-card:hover { border-color: #484f58; }\n    .change-header {\n      display: flex;\n      align-items: center;\n      gap: 10px;\n      padding: 11px 14px;\n      cursor: pointer;\n      user-select: none;\n    }\n    .change-file {\n      font-family: 'Courier New', monospace;\n      font-size: 12px;\n      color: var(--accent);\n      flex: 1;\n      min-width: 0;\n      overflow: hidden;\n      text-overflow: ellipsis;\n      white-space: nowrap;\n    }\n    .change-desc {\n      color: var(--text-muted);\n      font-size: 13px;\n      flex: 2;\n      min-width: 0;\n      overflow: hidden;\n      text-overflow: ellipsis;\n      white-space: nowrap;\n    }\n    .line-stats { font-size: 12px; font-family: monospace; white-space: nowrap; }\n    .chevron { color: var(--text-muted); font-size: 10px; transition: transform 0.15s; flex-shrink: 0; }\n    .change-card.open .chevron { transform: rotate(90deg); }\n    .change-body {\n      border-top: 1px solid var(--border);\n      padding: 16px;\n      display: none;\n    }\n    .change-card.open .change-body { display: block; }\n    .risk-reason { color: var(--text-muted); font-size: 13px; margin-bottom: 10px; }\n    .tags { display: flex; gap: 6px; flex-wrap: wrap; margin-bottom: 10px; }\n    .tag {\n      background: var(--surface-2);\n      border: 1px solid var(--border);\n      border-radius: 4px;\n      padding: 2px 8px;\n      font-size: 12px;\n      color: var(--text-muted);\n    }\n\n    /* \u2500\u2500 Diff viewer \u2500\u2500 */\n    .diff {\n      background: #0a0d10;\n      border: 1px solid var(--border);\n      border-radius: 6px;\n      padding: 12px;\n      font-family: 'Courier New', monospace;\n      font-size: 12px;\n      overflow-x: auto;\n      white-space: pre;\n      line-height: 1.5;\n    }\n    .dl { display: block; }\n    .dl.add { color: #3fb950; }\n    .dl.rem { color: #f85149; }\n    .dl.ctx { color: #8b949e; }\n    .dl.hdr { color: #79c0ff; }\n\n    /* \u2500\u2500 Components \u2500\u2500 */\n    .comp-card {\n      background: var(--surface);\n      border: 1px solid var(--border);\n      border-radius: 8px;\n      padding: 16px;\n      margin-bottom: 6px;\n      display: grid;\n      grid-template-columns: 180px 1fr auto;\n      gap: 16px;\n      align-items: start;\n    }\n    .comp-name { font-weight: 600; font-size: 14px; margin-bottom: 4px; }\n    .comp-desc { color: var(--text-muted); font-size: 13px; margin-bottom: 8px; }\n    .comp-files { font-family: monospace; font-size: 12px; color: var(--text-muted); }\n    .comp-file { display: block; padding: 1px 0; }\n\n    /* \u2500\u2500 Test coverage \u2500\u2500 */\n    .coverage-card {\n      background: var(--surface);\n      border: 1px solid var(--border);\n      border-radius: 8px;\n      padding: 20px;\n    }\n    .coverage-score {\n      font-size: 28px;\n      font-weight: 700;\n      text-transform: capitalize;\n      margin-bottom: 8px;\n    }\n    .coverage-score.high   { color: var(--low); }\n    .coverage-score.medium { color: var(--medium); }\n    .coverage-score.low    { color: var(--high); }\n    .coverage-score.none   { color: var(--high); }\n    .file-list { margin-top: 14px; }\n    .file-list-label {\n      font-size: 11px;\n      color: var(--text-muted);\n      text-transform: uppercase;\n      letter-spacing: 0.5px;\n      margin-bottom: 5px;\n    }\n    .cov-file { font-family: monospace; font-size: 12px; display: block; padding: 2px 0; }\n    .cov-file.fail { color: #f85149; }\n    .cov-file.pass { color: #3fb950; }\n\n    /* \u2500\u2500 Commits \u2500\u2500 */\n    .commit-item {\n      display: flex;\n      align-items: center;\n      gap: 12px;\n      padding: 10px 14px;\n      background: var(--surface);\n      border: 1px solid var(--border);\n      border-radius: 6px;\n      margin-bottom: 4px;\n    }\n    .commit-hash { font-family: monospace; font-size: 12px; color: var(--accent); width: 56px; flex-shrink: 0; }\n    .commit-msg  { flex: 1; font-size: 13px; }\n    .commit-meta { font-size: 12px; color: var(--text-muted); white-space: nowrap; }\n  </style>\n</head>\n<body>\n<div id=\"root\"></div>\n<script>\nconst DATA = __PR_DATA__;\n\nconst h = s => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');\n\nfunction riskBadge(r) {\n  const icons = { high: '\u26A0', medium: '~', low: '\u2713' };\n  const labels = { high: 'HIGH', medium: 'MED', low: 'LOW' };\n  return `<span class=\"risk ${r}\">${icons[r] || ''} ${labels[r] || r}</span>`;\n}\n\nfunction typeBadge(t) {\n  return `<span class=\"type-badge ${t}\">${h(t)}</span>`;\n}\n\nfunction renderDiff(snippet) {\n  if (!snippet) return '';\n  const lines = snippet.split('\\n').slice(0, 40).map(line => {\n    if (line.startsWith('@@'))       return `<span class=\"dl hdr\">${h(line)}</span>`;\n    if (line.startsWith('+'))        return `<span class=\"dl add\">${h(line)}</span>`;\n    if (line.startsWith('-'))        return `<span class=\"dl rem\">${h(line)}</span>`;\n    return `<span class=\"dl ctx\">${h(line)}</span>`;\n  }).join('');\n  return `<div class=\"diff\">${lines}</div>`;\n}\n\nfunction changeCard(c, id) {\n  const diff = c.diff_snippet ? renderDiff(c.diff_snippet) : '';\n  const components = (c.components || []).map(t => `<span class=\"tag\">${h(t)}</span>`).join('');\n  return `\n    <div class=\"change-card\" id=\"cc-${id}\">\n      <div class=\"change-header\" onclick=\"toggle('cc-${id}')\">\n        <span class=\"chevron\">\u25B6</span>\n        ${typeBadge(c.type)}\n        <span class=\"change-file\" title=\"${h(c.file)}\">${h(c.file)}</span>\n        <span class=\"change-desc\" title=\"${h(c.description)}\">${h(c.description)}</span>\n        <span class=\"line-stats\"><span class=\"added\">+${c.lines_added || 0}</span> <span class=\"removed\">-${c.lines_removed || 0}</span></span>\n        ${riskBadge(c.risk)}\n      </div>\n      <div class=\"change-body\">\n        ${c.risk_reason ? `<p class=\"risk-reason\">\u26A0 ${h(c.risk_reason)}</p>` : ''}\n        ${components ? `<div class=\"tags\">${components}</div>` : ''}\n        ${diff}\n      </div>\n    </div>`;\n}\n\nfunction render() {\n  const d = DATA;\n  const m = d.meta;\n  const genDate = new Date(m.generated_at).toLocaleString();\n\n  document.getElementById('root').innerHTML = `\n    <div class=\"header\">\n      <h1>PR Review: ${h(m.branch)}</h1>\n      <div class=\"branch-row\">\n        <span class=\"branch-pill\">${h(m.branch)}</span>\n        <span>\u2192</span>\n        <span class=\"branch-pill\">${h(m.target)}</span>\n        <span style=\"margin-left:8px\">Generated ${genDate}</span>\n      </div>\n      <div class=\"stats-bar\">\n        <div class=\"stat\">\n          <span class=\"stat-value\">${m.commit_count}</span>\n          <span class=\"stat-label\">Commits</span>\n        </div>\n        <div class=\"stat\">\n          <span class=\"stat-value\">${m.files_changed}</span>\n          <span class=\"stat-label\">Files changed</span>\n        </div>\n        <div class=\"stat\">\n          <span class=\"stat-value added\">+${m.insertions}</span>\n          <span class=\"stat-label\">Insertions</span>\n        </div>\n        <div class=\"stat\">\n          <span class=\"stat-value removed\">-${m.deletions}</span>\n          <span class=\"stat-label\">Deletions</span>\n        </div>\n        <div class=\"stat\" style=\"margin-left:auto\">\n          <span class=\"stat-value\">${riskBadge(d.overall_risk)}</span>\n          <span class=\"stat-label\">Overall risk</span>\n        </div>\n      </div>\n    </div>\n\n    <nav class=\"nav\">\n      <a href=\"#summary\">Summary</a>\n      <a href=\"#major\">Major (${d.major_changes.length})</a>\n      <a href=\"#minor\">Minor (${d.minor_changes.length})</a>\n      <a href=\"#components\">Components (${d.impacted_components.length})</a>\n      <a href=\"#coverage\">Test coverage</a>\n      <a href=\"#commits\">Commits (${d.commits.length})</a>\n    </nav>\n\n    <div class=\"main\">\n\n      <section class=\"section\" id=\"summary\">\n        <h2 class=\"section-title\">Executive Summary</h2>\n        <div class=\"summary-card\">${h(d.summary)}</div>\n      </section>\n\n      <section class=\"section\" id=\"major\">\n        <h2 class=\"section-title\">Major Changes <span class=\"count\">${d.major_changes.length}</span></h2>\n        ${d.major_changes.length\n          ? d.major_changes.map((c, i) => changeCard(c, 'maj' + i)).join('')\n          : '<p class=\"empty\">No major changes detected.</p>'}\n      </section>\n\n      <section class=\"section\" id=\"minor\">\n        <h2 class=\"section-title\">Minor Changes <span class=\"count\">${d.minor_changes.length}</span></h2>\n        ${d.minor_changes.length\n          ? d.minor_changes.map((c, i) => changeCard(c, 'min' + i)).join('')\n          : '<p class=\"empty\">No minor changes detected.</p>'}\n      </section>\n\n      <section class=\"section\" id=\"components\">\n        <h2 class=\"section-title\">Impacted Components <span class=\"count\">${d.impacted_components.length}</span></h2>\n        ${d.impacted_components.map(comp => `\n          <div class=\"comp-card\">\n            <div>\n              <div class=\"comp-name\">${h(comp.name)}</div>\n              ${riskBadge(comp.risk)}\n            </div>\n            <div>\n              <p class=\"comp-desc\">${h(comp.description)}</p>\n              <div class=\"comp-files\">\n                ${comp.files.map(f => `<span class=\"comp-file\">${h(f)}</span>`).join('')}\n              </div>\n            </div>\n          </div>\n        `).join('') || '<p class=\"empty\">No components identified.</p>'}\n      </section>\n\n      <section class=\"section\" id=\"coverage\">\n        <h2 class=\"section-title\">Test Coverage</h2>\n        <div class=\"coverage-card\">\n          <div class=\"coverage-score ${d.test_coverage.assessment}\">${d.test_coverage.assessment} coverage</div>\n          <p style=\"color:var(--text-muted);font-size:13px\">${h(d.test_coverage.notes)}</p>\n          ${d.test_coverage.untested_files?.length ? `\n            <div class=\"file-list\">\n              <div class=\"file-list-label\">Missing test coverage</div>\n              ${d.test_coverage.untested_files.map(f => `<span class=\"cov-file fail\">\u2717 ${h(f)}</span>`).join('')}\n            </div>` : ''}\n          ${d.test_coverage.test_files_changed?.length ? `\n            <div class=\"file-list\" style=\"margin-top:12px\">\n              <div class=\"file-list-label\">Test files modified</div>\n              ${d.test_coverage.test_files_changed.map(f => `<span class=\"cov-file pass\">\u2713 ${h(f)}</span>`).join('')}\n            </div>` : ''}\n        </div>\n      </section>\n\n      <section class=\"section\" id=\"commits\">\n        <h2 class=\"section-title\">Commits <span class=\"count\">${d.commits.length}</span></h2>\n        ${d.commits.map(c => `\n          <div class=\"commit-item\">\n            <span class=\"commit-hash\">${h(String(c.hash).substring(0, 7))}</span>\n            <span class=\"commit-msg\">${h(c.message)}</span>\n            <span class=\"commit-meta\">${h(c.author)} \u00B7 ${h(c.date)}</span>\n          </div>\n        `).join('')}\n      </section>\n\n    </div>\n  `;\n\n  // Highlight active nav link on scroll\n  const sections = ['summary','major','minor','components','coverage','commits'];\n  const navLinks = document.querySelectorAll('.nav a');\n  const observer = new IntersectionObserver(entries => {\n    entries.forEach(e => {\n      if (e.isIntersecting) {\n        navLinks.forEach(a => a.classList.remove('active'));\n        const link = document.querySelector(`.nav a[href=\"#${e.target.id}\"]`);\n        if (link) link.classList.add('active');\n      }\n    });\n  }, { rootMargin: '-20% 0px -70% 0px' });\n  sections.forEach(id => {\n    const el = document.getElementById(id);\n    if (el) observer.observe(el);\n  });\n}\n\nfunction toggle(id) {\n  document.getElementById(id)?.classList.toggle('open');\n}\n\nrender();\n</script>\n</body>\n</html>";
